            {
                id = "pedant", speaker = "Magister Cole",
                text = "*(He sniffs, your argument failing to meet his standard of rigor.)* A *spirited* reading. Poorly sourced. *(he makes a dismissive note.)* You reach for a conclusion the evidence does not yet support — the mark of the *amateur* emender. *(coolly.)* Bring me an *apparatus*, corruption, not a *sentiment*, and we'll speak. Until then, my thesis stands: you are an error, and errors, however eloquent, are for correcting. Good day.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Magister Cole",
                text = "*(Whatever you left him with, the bloodless scholar returns to his great critical apparatus of the cosmos — and you understand that you have either made an implacable editorial enemy or planted, in the most precise mind in Candlekeep, the one suggestion that could unravel the Wall from within: *that the deletions were never authorized, and the base text was destroyed to hide it.*)*",
            });

            NpcKeepColeDialogue = g;
        }
    }
}
